param([Parameter(Mandatory=$true)][string]$RunDirectory,[Parameter(Mandatory=$true)][string]$Destination,[Parameter(Mandatory=$true)][string]$BatchIdentity,[Parameter(Mandatory=$true)][string]$RunIdentifier)
$ErrorActionPreference='Stop';$required=@('compile.json','execution.json','compile.log','tester-journal.log','tester.htm','completion-marker.json','failure-marker.json','nora_phase2_time_rule_tester_v1.csv');function Hash($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()};if(Test-Path $Destination){throw 'occupied destination'};$tmp=$Destination+'.tmp-'+[guid]::NewGuid().ToString('N')
try{New-Item -ItemType Directory $tmp|Out-Null;foreach($n in $required){$s=Join-Path $RunDirectory $n;if(!(Test-Path $s -PathType Leaf)){throw "missing $n"};Copy-Item $s $tmp};$e=Get-Content (Join-Path $tmp 'execution.json') -Raw|ConvertFrom-Json;if($e.target_identifier-ne'time_rules'-or$e.run_identifier-ne$RunIdentifier-or$e.final_batch_identity-ne$BatchIdentity-or$e.collection_state-ne'complete'-or!$e.no_trading_operations){throw 'execution binding'};$c=Get-Content (Join-Path $tmp 'completion-marker.json') -Raw|ConvertFrom-Json;$f=Get-Content (Join-Path $tmp 'failure-marker.json') -Raw|ConvertFrom-Json;if(!$c.present-or$f.present){throw 'markers'};$inventory=@();foreach($n in $required){$p=Join-Path $tmp $n;$inventory+=@{path=$n;role=$n;size=(Get-Item $p).Length;sha256=Hash $p}};$inventory|ConvertTo-Json|Set-Content (Join-Path $tmp 'returned_inventory.json') -Encoding utf8;$m=[ordered]@{batch_identity=$BatchIdentity;completion_marker_present=$true;compiler_output_identity=$e.compiler_output_identity;ex5_sha256=$e.ex5_sha256;execution_packet_identity=$e.execution_packet_identity;failure_marker_present=$false;host_symbol=$e.host_symbol;returned_inventory_sha256=Hash (Join-Path $tmp 'returned_inventory.json');run_identifier=$RunIdentifier;schema_version='nora.time_rule_returned_package_v1';target_identifier='time_rules';timeframe='M1'};$json=$m|ConvertTo-Json -Compress;$m.returned_package_identity=[BitConverter]::ToString(([Security.Cryptography.SHA256]::Create()).ComputeHash([Text.Encoding]::UTF8.GetBytes($json))).Replace('-','').ToLowerInvariant();$m|ConvertTo-Json|Set-Content (Join-Path $tmp 'returned_result_manifest.json') -Encoding utf8;Move-Item $tmp $Destination}catch{Remove-Item $tmp -Recurse -Force -ErrorAction SilentlyContinue;throw}
